// Datos centrales de las experiencias y utilidades comunes
const DOMURA = (function(){
  const experiences = [
    {
      id:'essential',
      name:'Essential',
      pricePerPerson:28,
      short:'Pack esencial: elegancia accesible para encuentros íntimos.',
      description:'Una selección cuidadosa de platos pensados para quienes buscan una experiencia estética y sabrosa sin complejidad. Presentación cuidada y recetas fáciles de montar.',
      image:'https://images.unsplash.com/photo-1504674900247-0877df9cc836?q=80&w=1400&auto=format&fit=crop&ixlib=rb-4.0.3&s=7a3b8b0d4b1b0c6c1e7f2a3f1d3c2b9f',
      whatsInside:['Entrante frío','Plato principal envasado al vacío','Salsa preparada','Instrucciones de presentación']
    },
    {
      id:'curated',
      name:'Curated',
      pricePerPerson:45,
      short:'Selección curada con toques de sofisticación.',
      description:'Un menú con elaboraciones más trabajadas, ingredientes seleccionados y un mayor componente estético para crear un ritual en la mesa.',
      image:'https://images.unsplash.com/photo-1543353071-087092ec393c?q=80&w=1400&auto=format&fit=crop&ixlib=rb-4.0.3&s=3da4f3d2c0f9e4b8b0c5b3a7c5a6b7d8',
      whatsInside:['Aperitivo','Dos pases principales','Salsa gourmet','Instrucciones de montaje']
    },
    {
      id:'signature',
      name:'Signature',
      pricePerPerson:72,
      short:'La reinterpretación de códigos de alta cocina en casa.',
      description:'Platos diseñados para sorprender: técnicas, presentación y componentes que recrean la sensación de una experiencia alta gama en tu salón.',
      image:'https://images.unsplash.com/photo-1543352634-3c6f3a9c2f3a?q=80&w=1400&auto=format&fit=crop&ixlib=rb-4.0.3&s=f44c6d0db6ef3f4e8a9f0d9b1d2f7c3a',
      whatsInside:['Aperitivo especial','Tres pases principales','Postre sofisticado','Salsas y acabados','Guía de emplatado']
    },
    {
      id:'limited',
      name:'Limited',
      pricePerPerson:120,
      short:'Edición limitada: experiencias únicas y estéticas.',
      description:'Propuesta para ocasiones especiales: ingredientes exclusivos, emplatados y elementos sensoriales para una experiencia memorable y limitada.',
      image:'https://images.unsplash.com/photo-1528731708534-816fe59f90a7?q=80&w=1400&auto=format&fit=crop&ixlib=rb-4.0.3&s=be7b1f2a5b7d8f6e1c2b3a4d5e6f7a8b',
      whatsInside:['Selección premium','Elementos de montaje','Detalles de presentación','Guía paso a paso','Acceso a extras limitados']
    }
  ];

  function getAll(){return experiences}
  function getById(id){return experiences.find(e=>e.id===id)}

  /* CART - guarda en localStorage */
  function getCart(){
    try{return JSON.parse(localStorage.getItem('domura_cart')||'[]')}
    catch(e){return []}
  }
  function saveCart(cart){localStorage.setItem('domura_cart',JSON.stringify(cart)); updateCartCount();}
  function addToCart(item){
    const cart = getCart();
    cart.push(item);
    saveCart(cart);
  }
  function clearCart(){localStorage.removeItem('domura_cart'); updateCartCount();}

  function updateCartCount(){
    const badge = document.getElementById('cart-count');
    if(!badge) return;
    const n = getCart().length;
    badge.textContent = n>0? n.toString():'';
  }

  return {getAll,getById,getCart,saveCart,addToCart,clearCart,updateCartCount};
})();

/* Small toast implementation (no CSS dependency) */
function ensureToastRoot(){
  if(document.getElementById('toast-root')) return;
  const tr = document.createElement('div');
  tr.id = 'toast-root';
  tr.style.position = 'fixed';
  tr.style.bottom = '24px';
  tr.style.right = '24px';
  tr.style.zIndex = 9999;
  tr.style.display = 'flex';
  tr.style.flexDirection = 'column';
  tr.style.gap = '10px';
  document.body && document.body.appendChild(tr);
}

function showToast(msg, {type='info', timeout=3000} = {}){
  try{ ensureToastRoot(); } catch(e) { return }
  const tr = document.getElementById('toast-root');
  if(!tr) return;
  const t = document.createElement('div');
  t.className = 'toast '+type;
  t.textContent = msg;
  t.style.background = type==='success'? 'var(--accent)' : (type==='error'? '#b24b4b' : 'rgba(255,255,255,0.04)');
  t.style.color = type==='success'? 'var(--black)' : 'var(--cream)';
  t.style.padding = '10px 14px';
  t.style.borderRadius = '8px';
  t.style.boxShadow = '0 8px 30px rgba(0,0,0,0.6)';
  t.style.maxWidth = '360px';
  t.style.fontSize = '0.95rem';
  t.style.opacity = '1';
  t.style.transition = 'opacity 300ms ease';
  tr.appendChild(t);
  setTimeout(()=>{ t.style.opacity='0'; setTimeout(()=>t.remove(),300) }, timeout);
}

window.showToast = showToast;

/* UI behaviours globales */
document.addEventListener('DOMContentLoaded',()=>{
  ensureToastRoot();
  // nav toggle for small screens
  const toggle = document.getElementById('nav-toggle');
  if(toggle){
    toggle.addEventListener('click',()=>{
      const nav = document.querySelector('.main-nav');
      if(nav.style.display==='flex'){nav.style.display='none'} else {nav.style.display='flex';nav.style.flexDirection='column';nav.style.background='rgba(0,0,0,0.6)';nav.style.padding='12px';nav.style.position='absolute';nav.style.right='18px';nav.style.top='64px';}
    })
  }

  // put cart count badge in header if not present
  const header = document.querySelector('.header-inner');
  if(header && !document.getElementById('cart-count')){
    const a = document.querySelector('.main-nav a[href$="cart.html"]') || document.createElement('a');
    if(a){
      const span = document.createElement('span');
      span.id='cart-count';
      span.style.marginLeft='8px';
      span.style.background='var(--accent)';
      span.style.color='var(--black)';
      span.style.padding='3px 7px';
      span.style.borderRadius='999px';
      span.style.fontWeight='700';
      span.style.fontSize='0.85rem';
      if(a.parentNode) a.parentNode.insertBefore(span,a.nextSibling);
    }
  }
  DOMURA.updateCartCount();
});

/* Helper to render experiences list (used by experiences.html) */
function renderExperiencesList(containerSelector){
  const container = document.querySelector(containerSelector);
  if(!container) return;
  const list = DOMURA.getAll();
  container.innerHTML = list.map(exp=>`
    <article class="experience-card">
      <img src="${exp.image}" alt="${exp.name}">
      <div class="card-body">
        <h3>${exp.name}</h3>
        <p class="muted-small">${exp.short}</p>
        <p style="margin-top:10px"><strong>Desde €${exp.pricePerPerson}/persona</strong></p>
        <p style="margin-top:12px"><a class="btn btn-ghost" href="experience.html?id=${exp.id}">Ver experiencia</a>
        <a class="btn btn-primary" href="#" data-add="${exp.id}" style="margin-left:8px">Añadir</a></p>
      </div>
    </article>
  `).join('');

  // attach add buttons
  container.querySelectorAll('[data-add]').forEach(btn=>{
    btn.addEventListener('click',e=>{
      e.preventDefault();
      const id = btn.getAttribute('data-add');
      const exp = DOMURA.getById(id);
      if(!exp) return;
      // default 2 comensales
      DOMURA.addToCart({id:exp.id,name:exp.name,pricePerPerson:exp.pricePerPerson,guests:2});
      showToast(`${exp.name} añadido al carrito`,{type:'success'});
      DOMURA.updateCartCount();
    })
  })
}

/* Helper to render detail on experience.html */
function renderExperienceDetail(){
  const params = new URLSearchParams(location.search);
  const id = params.get('id');
  const container = document.getElementById('experience-detail');
  if(!container) return;
  const exp = DOMURA.getById(id) || DOMURA.getAll()[0];
  container.innerHTML = `
    <div class="experience-card">
      <img src="${exp.image}" alt="${exp.name}">
      <div class="card-body">
        <h2>${exp.name}</h2>
        <p class="muted-small">${exp.description}</p>
        <h4>Qué viene en cada pack</h4>
        <ul>
          ${exp.whatsInside.map(i=>`<li>${i}</li>`).join('')}
        </ul>
        <p><strong>Desde €${exp.pricePerPerson}/persona</strong></p>
        <label>Comensales
          <input type="number" id="guests" min="1" value="2" class="input" style="width:120px;margin-top:8px">
        </label>
        <p style="margin-top:12px"><a id="add-to-cart" class="btn btn-primary" href="#">Agregar al carrito</a></p>
      </div>
    </div>
  `;

  document.getElementById('add-to-cart').addEventListener('click',e=>{
    e.preventDefault();
    const guests = parseInt(document.getElementById('guests').value||2,10);
    DOMURA.addToCart({id:exp.id,name:exp.name,pricePerPerson:exp.pricePerPerson,guests});
    showToast(`${exp.name} añadido (${guests} comensales)`,{type:'success'});
    DOMURA.updateCartCount();
  })
}

/* Simple helper to render cart page */
function renderCart(){
  const container = document.getElementById('cart-root');
  if(!container) return;
  const cart = DOMURA.getCart();
  if(cart.length===0){
    container.innerHTML = `<p class="muted-small">Tu carrito está vacío. <a href="experiences.html">Ver experiencias</a></p>`;
    return;
  }
  const rows = cart.map((it,idx)=>{
    const subtotal = (it.pricePerPerson* (it.guests||1)).toFixed(2);
    return `
      <div class="cart-item">
        <div style="flex:1">
          <strong>${it.name}</strong>
          <div class="muted-small">€${it.pricePerPerson}/persona · ${it.guests||1} comensales</div>
        </div>
        <div style="text-align:right">
          <div><strong>€${subtotal}</strong></div>
          <div style="margin-top:6px"><button data-remove="${idx}" class="btn btn-ghost">Eliminar</button></div>
        </div>
      </div>
    `
  }).join('');

  const total = cart.reduce((s,it)=>s + (it.pricePerPerson*(it.guests||1)),0).toFixed(2);
  container.innerHTML = `
    <div class="cart-list">${rows}</div>
    <div style="margin-top:18px;text-align:right">
      <div class="muted-small">Total</div>
      <h3>€${total}</h3>
      <a href="#" id="checkout" class="btn btn-primary">Proceder al pago</a>
      <a href="#" id="clear-cart" class="btn btn-ghost" style="margin-left:8px">Vaciar carrito</a>
    </div>
  `;

  container.querySelectorAll('[data-remove]').forEach(btn=>{
    btn.addEventListener('click',()=>{
      const idx = parseInt(btn.getAttribute('data-remove'),10);
      const c = DOMURA.getCart();
      c.splice(idx,1);
      DOMURA.saveCart(c);
      renderCart();
    })
  })

  const clearBtn = document.getElementById('clear-cart');
  clearBtn && clearBtn.addEventListener('click',e=>{e.preventDefault();DOMURA.clearCart();renderCart();showToast('Carrito vaciado',{type:'success'})});

  const checkout = document.getElementById('checkout');
  checkout && checkout.addEventListener('click',e=>{
    e.preventDefault();
    // simple: navigate to cart steps (same page could have form). We'll go to cart.html with query step=checkout handled within cart page.
    window.location.href = 'cart.html?step=checkout';
  })
}

/* Expose helpers for page scripts */
window.DOMURA = DOMURA;
window.renderExperiencesList = renderExperiencesList;
window.renderExperienceDetail = renderExperienceDetail;
window.renderCart = renderCart;
